using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

public record TicketRequest(string Subject, string Description, int Priority);

public record ClassificationResult(string Category, Dictionary<string, float> Confidence);

public record CategoryLabels(string[] Labels);

using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public static class ModelTrainer
{
    public record TrainingMetrics(
        double MacroAccuracy,
        double MicroAccuracy,
        double LogLoss,
        double LogLossReduction,
        string ConfusionMatrix,
        string[] Labels);

    public static TrainingMetrics TrainAndEvaluate(string dataPath, string modelPath)
    {
        var mlContext = new MLContext(seed: 42);

        var data = mlContext.Data.LoadFromTextFile<TicketInput>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = mlContext.Transforms.Text
            .FeaturizeText("SubjectFeaturized", nameof(TicketInput.Subject))
            .Append(mlContext.Transforms.Text
                .FeaturizeText("DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .Append(mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketInput.Category)))
            .Append(mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        var model = pipeline.Fit(split.TrainSet);

        // Evaluate on held-out test set
        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions);

        // Extract label-to-index mapping from the trained model
        var engine = mlContext.Model.CreatePredictionEngine<TicketInput, TicketPrediction>(model);
        var scoreColumn = engine.OutputSchema["Score"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        scoreColumn.GetSlotNames(ref slotNames);
        var labels = slotNames.DenseValues().Select(v => v.ToString()).ToArray();

        mlContext.Model.Save(model, data.Schema, modelPath);

        return new TrainingMetrics(
            metrics.MacroAccuracy,
            metrics.MicroAccuracy,
            metrics.LogLoss,
            metrics.LogLossReduction,
            metrics.ConfusionMatrix.GetFormattedConfusionTable(),
            labels);
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/tickets")]
public class TicketsController(
    PredictionEnginePool<TicketInput, TicketPrediction> predictionEnginePool,
    CategoryLabels categoryLabels) : ControllerBase
{
    [HttpPost("classify")]
    public IActionResult Classify([FromBody] TicketRequest request)
    {
        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority,
        };

        var prediction = predictionEnginePool.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < categoryLabels.Labels.Length && i < prediction.Score.Length; i++)
        {
            confidence[categoryLabels.Labels[i]] = prediction.Score[i];
        }

        return Ok(new ClassificationResult(prediction.Category, confidence));
    }
}

