using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "tickets.csv");
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "model.zip");

// Train model and evaluate at startup
var trainingResult = ModelTrainer.TrainAndEvaluate(dataPath, modelPath);

builder.Services.AddSingleton(new CategoryLabels(trainingResult.Labels));

// Thread-safe prediction engine pool (never use singleton PredictionEngine in ASP.NET Core)
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.Logger.LogInformation("=== Ticket Classifier Model Metrics ===");
app.Logger.LogInformation("Macro Accuracy:     {MacroAccuracy:F4}", trainingResult.MacroAccuracy);
app.Logger.LogInformation("Micro Accuracy:     {MicroAccuracy:F4}", trainingResult.MicroAccuracy);
app.Logger.LogInformation("Log Loss:           {LogLoss:F4}", trainingResult.LogLoss);
app.Logger.LogInformation("Log Loss Reduction: {LogLossReduction:F4}", trainingResult.LogLossReduction);
app.Logger.LogInformation("Confusion Matrix:\n{ConfusionMatrix}", trainingResult.ConfusionMatrix);

app.MapControllers();
app.Run();

