using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/tickets")]
public class TicketsController(
    PredictionEnginePool<TicketInput, TicketPrediction> predictionEnginePool,
    CategoryLabels categoryLabels) : ControllerBase
{
    [HttpPost("classify")]
    public IActionResult Classify([FromBody] TicketRequest request)
    {
        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority,
        };

        var prediction = predictionEnginePool.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < categoryLabels.Labels.Length && i < prediction.Score.Length; i++)
        {
            confidence[categoryLabels.Labels[i]] = prediction.Score[i];
        }

        return Ok(new ClassificationResult(prediction.Category, confidence));
    }
}

